// Create all three tables if they don't exist yet
msg.topic = `
  CREATE TABLE IF NOT EXISTS sensor_readings (
    id        INTEGER PRIMARY KEY AUTOINCREMENT,
    ts        DATETIME DEFAULT CURRENT_TIMESTAMP,
    temp      REAL,
    tds       REAL,
    turbidity REAL,
    species   TEXT
  );
  CREATE TABLE IF NOT EXISTS actuator_history (
    id        INTEGER PRIMARY KEY AUTOINCREMENT,
    ts        DATETIME DEFAULT CURRENT_TIMESTAMP,
    heat      INTEGER,
    filter    INTEGER,
    air       INTEGER,
    species   TEXT
  );
  CREATE TABLE IF NOT EXISTS system_alerts (
    id        INTEGER PRIMARY KEY AUTOINCREMENT,
    ts        DATETIME DEFAULT CURRENT_TIMESTAMP,
    level     TEXT,
    message   TEXT,
    species   TEXT
  );
`;
// CRITICAL FIX: Clear payload to avoid SQLITE_RANGE error
msg.payload = "";
return msg;

// --- 1. Save sensor data to memory (existing behaviour) ---
let data = msg.payload;
if (typeof data === 'string') {
    try { data = JSON.parse(data); } catch(e) {}
}
flow.set('latestData', data);

const d = data;
const species = flow.get('selectedFish') || 'tilapia';

// --- 2. Build SQL for SQLite ---
msg.topic = `INSERT INTO sensor_readings (temp, tds, turbidity, species)
  VALUES (${parseFloat(d.temp)||0}, ${parseFloat(d.tds)||0}, ${parseFloat(d.turbidity)||0}, '${species}');`;

// --- 3. Alert thresholds per species ---
const thresholds = {
  tilapia:    { tempMin:20, tempMax:32, tdsMax:600, turbMax:150 },
  pangasius:  { tempMin:22, tempMax:30, tdsMax:500, turbMax:200 },
  zebra_fish: { tempMin:20, tempMax:28, tdsMax:400, turbMax:100 }
};
const thr = thresholds[species] || thresholds.tilapia;
const alerts = [];

if (d.temp < thr.tempMin) alerts.push({ level:'WARNING', message:`Temperature too low: ${parseFloat(d.temp).toFixed(1)}°C (min ${thr.tempMin}°C)` });
if (d.temp > thr.tempMax) alerts.push({ level:'CRITICAL', message:`Temperature too high: ${parseFloat(d.temp).toFixed(1)}°C (max ${thr.tempMax}°C)` });
if (d.tds  > thr.tdsMax)  alerts.push({ level:'WARNING', message:`TDS too high: ${Math.round(d.tds)}ppm (max ${thr.tdsMax}ppm)` });
if (d.turbidity > thr.turbMax) alerts.push({ level:'CRITICAL', message:`Turbidity critical: ${parseFloat(d.turbidity).toFixed(1)}NTU (max ${thr.turbMax}NTU)` });

// Store pending alerts for follow-up processing
flow.set('pendingAlerts', alerts.map(a => ({
  topic: `INSERT INTO system_alerts (level, message, species) VALUES ('${a.level}','${a.message.replace(/'/g,"''")}','${species}');`
})));

// CRITICAL FIX: Clear payload to avoid SQLITE_RANGE error when using msg.topic
// The sqlite node will use msg.topic as the query and return results in msg.payload
msg.payload = "";

// Also store the original sensor data and species for the response builder
msg._sensorData = d;
msg._species = species;

return msg;

const pending = flow.get('pendingAlerts') || [];
if (pending.length === 0) return null;
// Send them one at a time by returning an array of messages
const msgs = pending.map(p => {
    const m = { topic: p.topic, payload: "" };
    return m;
});
return [msgs];

// Get actuator state (from memory or DB)
const actuatorState = flow.get('actuatorState') || { heat: false, filter: false, air: false };
const manual = flow.get('manualOverride') || { active: false };
const selectedFish = msg._species || flow.get('selectedFish') || 'tilapia';

msg.payload = {
    status: 'ok',
    species: selectedFish,
    override: manual.active,
    heat: actuatorState.heat,
    filter: actuatorState.filter,
    air: actuatorState.air
};
msg.statusCode = 200;
msg.headers = { 'Content-Type': 'application/json', 'Access-Control-Allow-Origin': '*' };
return msg;

const selectedFish = flow.get('selectedFish') || 'tilapia';

// Query the most recent sensor reading from the database
msg.topic = `SELECT temp, tds, turbidity, species FROM sensor_readings ORDER BY ts DESC LIMIT 1;`;
msg._selectedFish = selectedFish;

// CRITICAL FIX: Clear payload to avoid SQLITE_RANGE error
msg.payload = "";

return msg;

// msg.payload now contains the query result from sqlite node (array of rows)
const rows = msg.payload || [];
const latest = rows[0] || {};

const aiData = flow.get('aiData') || { detected_species:'--', count:0, avg_size:'0 cm', confidence:0 };
const selectedFish = msg._selectedFish || flow.get('selectedFish') || 'tilapia';
const actuatorState = flow.get('actuatorState') || { heat: false, filter: false, air: false };
const manual = flow.get('manualOverride') || { active: false };

msg.payload = {
  sensors: {
    temp:      parseFloat(latest.temp)      || 0,
    tds:       parseFloat(latest.tds)       || 0,
    turbidity: parseFloat(latest.turbidity) || 0
  },
  actuators: actuatorState,
  ai: aiData,
  selectedFish: selectedFish,
  mode: manual.active ? 'manual' : 'auto'
};
msg.headers = { 'Access-Control-Allow-Origin':'*', 'Content-Type':'application/json' };
return msg;

const type = msg.req.query.type || 'tilapia';
flow.set('selectedFish', type);
msg.payload = { status:'ok', species: type };
msg.headers = { 'Access-Control-Allow-Origin':'*', 'Content-Type':'application/json' };
return msg;

const d = msg.payload;
if (typeof d === 'string') {
    try { d = JSON.parse(d); } catch(e) {}
}

// Save to memory
const actuatorState = {
    heat:   d.heat   === true || d.heat   === 1,
    filter: d.filter === true || d.filter === 1,
    air:    d.air    === true || d.air    === 1
};
flow.set('actuatorState', actuatorState);
flow.set('manualOverride', {
    active: d.active === true,
    heat: actuatorState.heat,
    filter: actuatorState.filter,
    air: actuatorState.air
});

const species = flow.get('selectedFish') || 'tilapia';

// Build SQL for SQLite
msg.topic = `INSERT INTO actuator_history (heat, filter, air, species)
  VALUES (${actuatorState.heat?1:0}, ${actuatorState.filter?1:0}, ${actuatorState.air?1:0}, '${species}');`;

// CRITICAL FIX: Clear payload to avoid SQLITE_RANGE error
msg.payload = "";

return msg;

// ?range=1h|6h|24h|7d — defaults to 1h
const range = (msg.req.query.range || '1h');
const intervals = { '1h':'1 hour', '6h':'6 hours', '24h':'24 hours', '7d':'7 days' };
const since = intervals[range] || '1 hour';

msg.topic = `
  SELECT ts, temp, tds, turbidity, species
  FROM sensor_readings
  WHERE ts >= datetime('now', '-${since}')
  ORDER BY ts ASC
  LIMIT 500;
`;
// CRITICAL FIX: Clear payload
msg.payload = "";
return msg;

msg.headers = { 'Access-Control-Allow-Origin':'*', 'Content-Type':'application/json' };
// msg.payload is already the array of rows from sqlite node
msg.payload = msg.payload || [];
return msg;

msg.topic = `
  SELECT id, ts, level, message, species
  FROM system_alerts
  ORDER BY ts DESC
  LIMIT 50;
`;
// CRITICAL FIX: Clear payload
msg.payload = "";
return msg;

const range = (msg.req.query.range || '24h');
const intervals = { '1h':'1 hour', '6h':'6 hours', '24h':'24 hours', '7d':'7 days' };
const since = intervals[range] || '24 hours';
msg._csvRange = range;

msg.topic = `
  SELECT ts, temp, tds, turbidity, species
  FROM sensor_readings
  WHERE ts >= datetime('now','-${since}')
  ORDER BY ts ASC;
`;
// CRITICAL FIX: Clear payload
msg.payload = "";
return msg;

const rows = msg.payload || [];
let csv = 'timestamp,temperature_C,tds_ppm,turbidity_NTU,species\n';
rows.forEach(r => {
  csv += `${r.ts},${r.temp},${r.tds},${r.turbidity},${r.species}\n`;
});
msg.payload = csv;
msg.headers = {
  'Access-Control-Allow-Origin': '*',
  'Content-Type': 'text/csv',
  'Content-Disposition': `attachment; filename="aquarium_${msg._csvRange || '24h'}.csv"`
};
return msg;
